#include <stdio.h>

long long fastPow(long long base, int exp) {
    long long result = 1;
    while (exp > 0) {
        if (exp & 1) result *= base;
        base *= base;
        exp >>= 1;
    }
    return result;
}

long long power(int base, int exponent) {
    if (exponent < 0) {
        if(base == 1 || base == -1)
            return 1;
        else if(base == -1 && exponent % 2 == 0)
            return 1;
        else
            return 1.0 / power(base, -exponent);
    }
    return fastPow(base, exponent);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int b, e;
        scanf("%d %d", &b, &e);
        if (e < 0 && b == 0) printf("0\n");
        else printf("%lld\n", (long long)power(b, e));
    }
    return 0;
}

