import sys

def fast_pow(base, exp):
    result = 1
    while exp > 0:
        if exp & 1:
            result *= base
        base *= base
        exp >>= 1
    return result

def power(base, exponent):
    if exponent < 0:
        if base == 1 or base == -1:
            return 1
        elif base == -1 and exponent % 2 == 0:
            return 1
        elif base == 0:
            return 0
        else:
            return int(1.0 / power(base, -exponent))
    return fast_pow(base, exponent)

data = sys.stdin.read().strip().split()
if not data:
    sys.exit()
T = int(data[0])
idx = 1
out = []
for _ in range(T):
    b = int(data[idx]); e = int(data[idx+1]); idx += 2
    out.append(str(power(b, e)))
